class Solution {
public:
    int rob(vector<int>& nums) {
    int n = nums.size();
    int first;
    int second = nums[0];
    int third = nums[1];
    int cost = 0;


    for(int i = 2; i < n; i++){
        first = second;
        second = third;
        third = nums[i];

        if(first && second && third)
        if(first+third > second){
            cost += first;
            first = 0;
            second = 0;
        }
        else{
            cost += second;
            first = 0;
            second = 0;
            third = 0;
        }

    }
    cost += max(second, third);
    return cost;
    }
};

